import React from "react"
import Layout from "@components/layout"
import SEO from "@components/seo"
import { graphql } from "gatsby"
import "@styles/about.scss"

const AboutPage = ({ data }) => {
  const siteMetadata = data?.site?.siteMetadata

  if (!siteMetadata) {
    return (
      <Layout>
        <SEO title="About" />
      </Layout>
    )
  }

  const socialLinks = {
    GitHub: siteMetadata.social.github,
    Twitter: siteMetadata.social.twitter,
    LinkedIn: siteMetadata.social.linkedin,
  }

  return (
    <Layout>
      <SEO title="About" />
      <div className="about-info">
        <h1 className="name">{siteMetadata.name}</h1>
        <div className="about-container">
          <a href={`mailto:${siteMetadata.mail}`} className="mail">
            {siteMetadata.mail}
            <span>,</span>
          </a>
          <ul className="social-links">
            {Object.keys(socialLinks).map((key, index) => (
              <li key={key}>
                <a
                  href={socialLinks[key]}
                  target="_blank"
                >
                  {key}
                  {index < Object.keys(socialLinks).length - 1 && (
                    <span>,</span>
                  )}
                </a>
              </li>
            ))}
          </ul>
        </div>
        <p className="desc">
          서비스와 사용자를 잇는 인터페이스를 만들 때 즐거움을 느끼는 웹
          개발자입니다. 기술로 더 나은 세상을 만들고자 하는 활동에 관심이
          많습니다.
        </p>
      </div>
    </Layout>
  )
}
export default AboutPage

export const query = graphql`
  query {
    site {
      siteMetadata {
        title
        name
        mail
        social {
          github
          twitter
          linkedin
        }
      }
    }
  }
`
